import React, { useState } from "react";
import "./index.css";

import iconStar from "./images/icon-star.svg";
import illustrationThankYou from "./images/illustration-thank-you.svg";

function RatingApp() {
  const [rating, setRating] = useState(null);
  const [status, setStatus] = useState("rating");
  const [comment, setComment] = useState("");

  const goToConfirm = () => {
    if (rating !== null) setStatus("confirming");
  };

  const handleFinalSubmit = () => {
    setStatus("submitted");
  };

  const handleDecline = () => {
    setStatus("declined-options");
  };

  if (status === "submitted") {
    return (
      <main className="container">
        <div className="card thank-you">
          <img
            src={illustrationThankYou}
            alt="Zahvala"
            className="img-thank-you"
          />
          {rating && (
            <div className="selection-badge">Odabrali ste {rating} od 5</div>
          )}
          <h1>Hvala vam!</h1>
          <p>Vaše povratne informacije su nam dragocjene.</p>
        </div>
      </main>
    );
  }

  if (status === "declined-options") {
    return (
      <main className="container">
        <div className="card">
          <h1>Što želite učiniti?</h1>
          <div className="confirm-buttons">
            <button className="submit-btn" onClick={() => setStatus("rating")}>
              OCIJENI PONOVNO
            </button>

            <div className="decline-section">
              <p>Ne želite nas ocijeniti? Recite nam zašto (opcionalno):</p>
              <textarea
                className="comment-box"
                placeholder="Vaš komentar..."
                value={comment}
                onChange={(e) => setComment(e.target.value)}
              />
              <button
                className="back-btn full-width"
                onClick={() => {
                  setRating(null);
                  setStatus("submitted");
                }}
              >
                NE ŽELIM OCIJENITI
              </button>
            </div>
          </div>
        </div>
      </main>
    );
  }

  if (status === "confirming") {
    return (
      <main className="container">
        <div className="card thank-you">
          <h1>Jeste li sigurni?</h1>
          <div className="confirm-display">
            <span className="text-light">Vaša ocjena:</span>
            <span className="rating-token">{rating}</span>
          </div>
          <div className="confirm-buttons">
            <button className="submit-btn" onClick={handleFinalSubmit}>
              DA
            </button>
            <button className="back-btn" onClick={handleDecline}>
              NE
            </button>
          </div>
        </div>
      </main>
    );
  }

  return (
    <main className="container">
      <div className="card">
        <div className="icon-box">
          <img src={iconStar} alt="Zvijezda" />
        </div>
        <h1>Kako smo prošli?</h1>
        <p>
          Molimo vas da nas ocijenite. Svaka povratna informacija je dobrodošla!
        </p>
        <div className="rating-row">
          {[1, 2, 3, 4, 5].map((num) => (
            <button
              key={num}
              className={`circle-btn ${rating === num ? "active" : ""}`}
              onClick={() => setRating(num)}
            >
              {num}
            </button>
          ))}
        </div>
        <button
          className="submit-btn"
          onClick={goToConfirm}
          disabled={rating === null}
        >
          POŠALJI
        </button>
      </div>
    </main>
  );
}

export default RatingApp;
